svg.script:
const dropZone = document.getElementById("dropZone");

// Highlight effect
function setHighlight(on) {
  dropZone.style.fill = on ? "#3b82f6" : "#1f2937";
  dropZone.style.opacity = on ? "0.3" : "1";
}

// Prevent default drag behaviors
["dragenter", "dragover", "dragleave", "drop"].forEach(event => {
  document.addEventListener(event, e => e.preventDefault(), false);
});

document.addEventListener("dragover", () => setHighlight(true));
document.addEventListener("dragleave", () => setHighlight(false));

document.addEventListener("drop", (e) => {
  setHighlight(false);

  const file = e.dataTransfer.files[0];
  if (!file) return;

  // Only allow HTML files
  if (!file.name.endsWith(".html")) {
    alert("Please drop an .html file");
    return;
  }

  const reader = new FileReader();

  reader.onload = function(event) {
    const htmlContent = event.target.result;

    // Open new about:blank tab
    const win = window.open("about:blank");

    if (!win) {
      alert("Popup blocked! Allow popups and try again.");
      return;
    }

    win.document.open();
    win.document.write(htmlContent);
    win.document.close();
  };

  reader.readAsText(file);
});
